v_{*}(s) &amp;amp;= \sum_{a=\pi_{*}(s)} \pi_{*} (a|s)\sum_{s&amp;#x27;}\sum_{r}p(s&amp;#x27;,r|s,a)[r+\gamma v_{*} (s&amp;#x27;)]\\
&amp;amp;= \max_{a}\sum_{s&amp;#x27;}\sum_{r}p(s&amp;#x27;,r|s,a)[r+\gamma v_{*} (s&amp;#x27;)]
\end{aligned}
